VALUES
  ('immigration-1aab856d-moex-00170', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'essay', '依據我國《入出國及移民法》規定，內政部移民署受理外國人在臺灣地
區申請停留、居留或永久居留時，得於受理申請當時或擇期與申請人面
談。同時為保障外國人之權益，面談於經查驗許可入國（境）後進行者，
外國人於接受面談時，得委任律師在場。試說明在此情況下許可律師在
場及其限制或禁止之相關規定為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00171', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'essay', '甲購入一輛電動自行車，並改裝以提升馬力，時速可達一百公里。甲傍
晚駕駛該車外出購物，遵守速限行駛於慢車道，卻因為路人乙突然從右
前方巷口跑到車道上，甲煞車不及撞倒乙，乙傷重臥地不起。甲跑到附
近的超商，謊稱自己看到車禍，請店員幫忙電召救護車，直到乙被救護
車載走才離開。雖然送醫時間沒有延誤，乙仍因車禍顱內出血，於醫院
急診室死亡。警方調閱監視錄影發現甲應是肇事者，卻故意以證人身分
通知甲到警局說明。甲誤以為自己有據實陳述的義務，怕受到偽證罪的
處罰，遂坦承自己就是騎車撞倒乙的人。案件移送地檢署後，檢察官以
被告身分訊問甲，甲始終保持緘默，但檢察官以甲的警詢筆錄與監視錄
影等證據起訴甲。試問：
甲的刑責如何？（15 分）
甲的警詢自白有無證據能力？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00172', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '依據現行《人口販運防制法》之相關規定，有關人口販運被害人鑑別事項，下列何者正確？', '["司法警察人員進行人口販運被害人之判斷，如有疑義時，應與檢察官研商", "檢察官進行人口販運被害人之判斷，如有疑義時，應與社工人員或其他協助鑑別人員研商", "法院審理中，知悉有人口販運嫌疑者，應即移請檢察官轉請司法警察機關（單位）鑑別", "經司法警察人員鑑別為人口販運被害人者，檢察官得視案情進展，自行再將被害人鑑別為非被 害人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00173', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '依據《海峽兩岸共同打擊犯罪及司法互助協議》，有關海峽兩岸司法互助的請求程序，下列敘述 何者正確？', '["若執行請求將妨礙正在進行之偵查、起訴或審判程序，可暫緩提供協助", "不得因請求內容不符合己方規定而不予協助", "請求應透過外交部轉請法務部辦理", "對請求協助與執行請求的相關資料應予以公開，以昭公信"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00174', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '依據《國際刑事司法互助法》，有關我國提出刑事司法互助請求之程序，下列敘述何者正確？', '["司法警察官得直接向法務部提出申請", "一般民眾得自行直接向法務部提出申請", "偵查階段由檢察官向法務部提出申請", "審判階段由檢察總長提出申請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00175', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '為保障人口販運被害人之人權，有效防制人口販運犯罪，目前行政院特設下列何者，掌理防制人 口販運相關事項？', '["行政院防制人口販運會報", "行政院防制人口販運及消除種族歧視協調會報", "行政院防制消除種族歧視協調會報", "行政院防制人口販運辦公室"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00176', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '內政部移民署執行職務人員於入出國（境）查驗時，若有事實足認當事人有違法情事者，得暫時 將其留置於勤務處所。有關該留置處分，下列敘述何者正確？', '["實施暫時留置時間，對國民不得逾二小時", "實施暫時留置時間，對外國人、大陸地區人民、香港或澳門居民不得逾四小時", "對當事人實施之暫時留置，即使目的達成或已無必要，仍得繼續留置四小時，以便進行最終確認", "實施暫時留置時間，對香港或澳門居民不得逾二小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00177', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '外國人經鑑別為人口販運被害人者，有關其居留申請之規定，下列何者錯誤？', '["中央主管機關應依其申請，核發一年效期之居留許可", "人口販運被害人依規定經許可居留後，其居留期間應列入得依其他法律規定申請長期居留、永 久居留、定居或歸化所定居留期間之計算", "人口販運被害人依其他法律有關居留之規定，較有利於依人口販運防制法之申請居留許可者， 從其規定", "經核發居留許可之人口販運被害人得逕向中央勞動主管機關申請工作許可，不受就業服務法之 限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00178', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '涉外執法案件中，時常必須運用通譯人員協助進行案件調查。試問依據內政部移民署有關通譯人 員運用之規定，下列敘述何者正確？', '["為案情溝通迅速，通譯人員可視案情發表個人意見", "通譯人員對運用通譯單位不合理之要求得予以拒絕，並立即向所屬單位或派遣單位反映", "通譯服務過程中，任何人不得全程錄音或錄影", "通譯人員得與當事人私下餐飲應酬，運用通譯單位不得干涉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00179', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '為偵辦跨國性毒品犯罪，依法得進行控制下交付的偵查手段，依我國相關法令規定，該偵查計畫 書應經下列何者核可後核發？', '["內政部警政署署長", "法務部部長", "最高法院院長", "最高檢察署檢察總長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
